import { ref } from "@vue/reactivity";
import { releasedList } from '../../../../server/http/api/user'
import { addKey } from '../../../../utils/addKey'
const taskList = ref([])
export const total = ref(0);

export function getreleasedList(options?: any) {
  if (options) {
    //console.log('options', options);

    releasedList(options).then((res: any) => {
      if (res.data.code === 200) {
        taskList.value = res.data.data.list
        total.value = res.data.data.total

      }
    })
  } else {
    releasedList({}).then((res: any) => {
      if (res.data.code === 200) {
        taskList.value = res.data.data.list
        total.value = res.data.data.total

      }
    })
  }

  return taskList
}
export function search(form: any) {
  getreleasedList(form)
}