
import { defineComponent, reactive, toRaw, toRefs, watch } from "vue";
import { getTime } from "../../../utils/setData";
export default defineComponent({
  setup(props, ctx) {
    const formState: any = reactive({
      entrustmentNo: "",
      entrustCompany: "",
      entrustPeople: "",
      businessAcceptor: "",
      dateInterval: [],
    });

    let timer: any;
    watch(
      formState,
      (newval, o) => {
        //console.log(newval);

        clearTimeout(timer);
        timer = setTimeout(() => {
          let form: any = {};
          Object.assign(form, toRaw(formState));
          //console.log(formState.dateInterval.length);

          if (formState.dateInterval.length == 2) {
            Object.assign(form, {
              dateInterval:
                getTime(newval.dateInterval[0]) +
                "~" +
                getTime(newval.dateInterval[1]),
            });
            ctx.emit("searchTask", form);
          } else if (formState.dateInterval.length == 0) {
            Object.assign(form, {
              dateInterval: null,
            });
            ctx.emit("searchTask", form);
          } else {
            ctx.emit("searchTask", form);
          }
        }, 600);
      },
      {}
    );

    //   let timer: any;
    // watch(formState, (newval, o) => {
    //   clearTimeout(timer);
    //   timer = setTimeout(() => {
    //     let form: any = {};
    //     Object.assign(form, toRaw(formState));
    //     if (formState.dateInterval) {
    //       form.dateInterval =
    //         getTime(newval.receivedDate[0]) +
    //         "~" +
    //         getTime(newval.receivedDate[1]);
    //     }
    //     ctx.emit("searchTask", form);
    //   }, 600);
    // });

    return {
      ...toRefs(formState),
    };
  },
});
