
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";
import { defineComponent } from "vue";
import { useRouter } from "vue-router";
const columns = [
  {
    dataIndex: "entrustmentNo",
    key: "entrustmentNo",
    title: "委托编号",
  },
  {
    title: "委托单位",
    dataIndex: "entrustCompany",
    key: "entrustCompany",
  },
  {
    title: "委托人",
    dataIndex: "entrustPeople",
    key: "entrustPeople",
  },
  {
    title: "受理人",
    key: "businessAcceptor",
    dataIndex: "businessAcceptor",
  },
  {
    title: "受理日期",
    key: "acceptanceDate",
    dataIndex: "acceptanceDate",
  },

  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

export default defineComponent({
  props: ["taskList"],
  setup(props, { emit }) {
    const pub = function (detail: any) {
      emit("pubTask", detail);
    };
    return {
      pub,
      columns,
    };
  },
  components: {
    SmileOutlined,
    DownOutlined,
  },
});
