
import { defineComponent, reactive, ref, toRefs, watch } from "vue";
import { useRouter } from "vue-router";
import SearchTaskalpub from "../../../components/ATaskdelegation/Taskalpub/SearchTaskalpub.vue";
import TableTaskalpub from "../../../components/ATaskdelegation/Taskalpub/TableTaskalpub.vue";
import { releasedList, publishTask } from "../../../server/http/api/user";
import {
  getreleasedList,
  search,
  total,
} from "./TaskalpubHook/getreleasedList";

export default defineComponent({
  name: "Taskalpub",
  components: { SearchTaskalpub, TableTaskalpub },
  setup() {
    const router = useRouter();
    let searchOptions = reactive({
      pageNum: 1,
      pageSize: 10,
    });

    // 获取任务列表
    let taskList = getreleasedList(searchOptions);
    // 查询任务列表
    function searchTask(from: any) {
      Object.assign(searchOptions, from);
      //console.log(123456);
      
    }
    watch(searchOptions, () => {
      //console.log(123);
      
      search({ ...searchOptions });
    });

    function pubTask(detail: any) {
      router.push({ name: "Pubtask", params: { id: detail.id } });
    }
    return {
      taskList,
      searchTask,
      pubTask,
      ...toRefs(searchOptions),
      total,
    };
  },
});
